using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    [TestMethod]
    [DataRow("1234567890", "(123) 456-7890")]
    [DataRow("5551234567", "(555) 123-4567")]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber(string digits, string expected)
    {
        var result = _formatter.FormatPhoneNumber(digits);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    [DataRow("1234567890")]
    [DataRow("9876543210")]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParentheses(string digits)
    {
        var result = _formatter.FormatPhoneNumber(digits);

        Assert.StartsWith($"({digits[..3]})", result);
    }

    [TestMethod]
    [DataRow("1234567890")]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits(string digits)
    {
        var result = _formatter.FormatPhoneNumber(digits);

        Assert.EndsWith(digits[6..], result);
    }

    [TestMethod]
    [DataRow("1234567890")]
    public void FormatPhoneNumber_ValidDigits_MatchesPhonePattern(string digits)
    {
        var result = _formatter.FormatPhoneNumber(digits);

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));

        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.FormatPhoneNumber(digits));
    }

    [TestMethod]
    [DataRow("Alice", "Mr.", "Dear Mr. Alice,")]
    [DataRow("Bob", "Dr.", "Dear Dr. Bob,")]
    public void BuildGreeting_WithNameAndTitle_ReturnsExpectedGreeting(string name, string title, string expected)
    {
        var result = _formatter.BuildGreeting(name, title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear Mr.", result);
    }

    [TestMethod]
    [DataRow("Alice")]
    [DataRow("Bob")]
    public void BuildGreeting_AnyName_EndsWithComma(string name)
    {
        var result = _formatter.BuildGreeting(name);

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    [DataRow("Alice")]
    public void BuildGreeting_AnyName_ContainsName(string name)
    {
        var result = _formatter.BuildGreeting(name);

        Assert.Contains(name, result);
    }

    [TestMethod]
    public void BuildGreeting_NullName_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.BuildGreeting(null!));
    }

    [TestMethod]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException(string name)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.BuildGreeting(name));
    }

    [TestMethod]
    [DataRow("Hello World", "hello-world")]
    [DataRow("My Blog Post!", "my-blog-post")]
    [DataRow("  Spaces Around  ", "spaces-around")]
    [DataRow("UPPERCASE TITLE", "uppercase-title")]
    [DataRow("multiple---dashes", "multiple-dashes")]
    public void GenerateSlug_ValidTitle_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    [DataRow("Hello World")]
    [DataRow("Test Post 123")]
    public void GenerateSlug_ValidTitle_MatchesSlugPattern(string title)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    public void GenerateSlug_NullTitle_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.GenerateSlug(null!));
    }

    [TestMethod]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_WhitespaceTitle_ThrowsArgumentException(string title)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.GenerateSlug(title));
    }

    [TestMethod]
    [DataRow(19.99, "$", "$19.99")]
    [DataRow(100.5, "€", "€100.50")]
    [DataRow(0, "$", "$0.00")]
    public void FormatCurrency_WithAmount_ReturnsFormattedString(double amount, string symbol, string expected)
    {
        var result = _formatter.FormatCurrency((decimal)amount, symbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    [DataRow("$")]
    [DataRow("€")]
    [DataRow("£")]
    public void FormatCurrency_WithSymbol_StartsWithSymbol(string symbol)
    {
        var result = _formatter.FormatCurrency(42.00m, symbol);

        Assert.StartsWith(symbol, result);
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    [DataRow(1.1, ".10")]
    [DataRow(1.126, ".13")]
    public void FormatCurrency_DecimalPlaces_EndsWithTwoDecimalDigits(double amount, string expectedEnd)
    {
        var result = _formatter.FormatCurrency((decimal)amount);

        Assert.EndsWith(expectedEnd, result);
    }

    [TestMethod]
    public void FormatCurrency_AnyAmount_MatchesCurrencyPattern()
    {
        var result = _formatter.FormatCurrency(1234.56m, "$");

        Assert.MatchesRegex(@"^\$\d+\.\d{2}$", result);
    }
}

